package cz.zamboch.distilled;

/**
 * Auto-generated embedded data file for first-battle fallback.
 * Contains 45,186 bytes of persistence data (VCS histograms,
 * tick budget ceiling, gun/movement stats) from training battles.
 *
 * <p>When no data file exists on the target machine (first battle),
 * the robot decodes this Base64 data to warm-start all persisted
 * subsystems with learned priors.</p>
 */
public final class DefaultDataFile {

    private DefaultDataFile() {}

    private static final String D0 = "";
    private static final String D1 = "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAABAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAABAAAAAQAAAAAAAgABAAAAAQADAAIAAQABAAAAAgABAAEAAAAAAAAAAAAAAAEAAAAAAAAAAQAAAAEAAAABAAEAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAQAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAABAAAAAAAA";
    private static final String DATA = D0 + D1;

    /**
     * Decode the embedded data file to a byte array.
     *
     * @return raw persistence bytes, or empty array on decode failure
     */
    public static byte[] decode() {
        try {
            return java.util.Base64.getDecoder().decode(DATA);
        } catch (Exception e) {
            return new byte[0];
        }
    }
}
